import java.util.Arrays;

public class Main {

    static int linearSearch(int[] arr, int target) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) {
                return i;
            }
        }
        return -1;
    }

    static int binarySearch(int[] arr, int target) {
        int left = 0;
        int right = arr.length - 1;

        while (left <= right) {
            int mid = (left + right) / 2;

            if (arr[mid] == target) {
                return mid;
            } else if (arr[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return -1;
    }

    public static void main(String[] args) {
        int[] numbers = {4, 12, 7, 23, 9, 1, 18};
        int target = 23;

        int linearResult = linearSearch(numbers, target);
        System.out.println("Dogrusal arama: " + target + " indeks " + linearResult + "'de bulundu");

        // Binary arama icin dizi siralanmali
        int[] sortedNumbers = numbers.clone();
        Arrays.sort(sortedNumbers);

        int binaryResult = binarySearch(sortedNumbers, target);
        System.out.println("Binary arama: " + target + " indeks " + binaryResult + "'de bulundu");

        int notFound = linearSearch(numbers, 99);
        System.out.println("\n99 araniyor (bulunamayacak): " + notFound);
    }
}
